{"path":"analyze.pl","content":"#!/usr/bin/perl
use strict;
use warnings;

# Parse FASTA
my %seqs;
my $name;
open my $fh, "<", "sequences.fasta" or die "Cannot open sequences.fasta: $!";
while (<$fh>) {
    chomp;
    if (/^>(\S+)/) {
        $name = $1;
        $seqs{$name} = "";
    } else {
        $next_seq = $_;
        $next_seq =~ s/^\s+|\s+$//g;
        next if $next_seq eq '';
        $seqs{$name} .= $next_seq;
    }
}
close $fh;

for my $k (sort keys %seqs) {
    print "$k: " . length($seqs{$k}) . " bp\n";
}

my $egfp = $seqs{"egfp"};
my $flag = $seqs{"flag"};
my $snap = $seqs{"snap"};
my $input = $seqs{"input"};
my $output = $seqs{"output"};

# Find positions of egfp, flag, snap in output
my $pos_egfp = index($output, $egfp);
my $pos_flag = index($output, $flag);
my $pos_snap = index($output, $snap);

print "\negfp position in output: $pos_egfp\n";
print "flag position in output: $pos_flag\n";
print "snap position in output: $pos_snap\n";

# Find what is right before egfp in output
if ($pos_egfp >= 0) {
    my $before = substr($output, 0, $pos_egfp);
    print "\nBefore egfp in output (last 50bp): " . substr($before, -50) . "\n";
}

# Find what is right after snap in output
if ($pos_snap >= 0) {
    my $after_start = $pos_snap + length($snap);
    my $after = substr($output, $after_start, 100);
    print "After snap in output (first 100bp): $after\n";
}

# Find what is between egfp and flag
if ($pos_egfp >= 0 && $pos_flag >= 0) {
    my $between = substr($output, $pos_egfp + length($egfp), $pos_flag - $pos_egfp - length($egfp));
    print "\nBetween egfp and flag: '$between'\n";
}

# Find what is between flag and snap
if ($pos_flag >= 0 && $pos_snap >= 0) {
    my $between = substr($output, $pos_flag + length($flag), $pos_snap - $pos_flag - length($flag));
    print "Between flag and snap: '$between'\n";
}

# Check if the output is input with egfp+flag+snap inserted at a specific point
print "\n--- Comparing input and output ---\n";
my $diff_start = -1;
my $min_len = length($input) < length($output) ? length($input) : length($output);
for my $i (0..$min_len-1) {
    if (substr($output, $i, 1) ne substr($input, $i, 1)) {
        $diff_start = $i;
        last;
    }
}
print "First difference from start: position $diff_start\n";
if ($diff_start >= 0) {
    print "Input at diff: ..." . substr($input, $diff_start-20, 40) . "...\n";
    print "Output at diff: ..." . substr($output, $diff_start-20, 40) . "...\n";
}

# Find last difference from end
my $diff_end_input = length($input);
my $diff_end_output = length($output);
for my $i (0..$min_len-1) {
    if (substr($output, length($output)-1-$i, 1) ne substr($input, length($input)-1-$i, 1)) {
        $diff_end_input = length($input) - $i;
        $diff_end_output = length($output) - $i;
        last;
    }
}
print "Last difference from end: input pos $diff_end_input, output pos $diff_end_output\n";

# The insertion point in the circular input
# Since input is circular, find where egfp starts in the circular context
my $combined = $input . substr($input, 0, length($egfp) + 10);
my $pos_egfp_circ = index($combined, $egfp);
print "\negfp position in circular input (extended): $pos_egfp_circ\n";

# The part of input that gets replaced
my $insertion_start = $pos_egfp_circ;
my $insertion_end = $pos_egfp_circ + length($egfp) + length($flag) + length($snap);
print "Insertion region in circular input: $insertion_start to $insertion_end\n";

# What is the sequence that gets replaced?
my $replaced_len = length($egfp) + length($flag) + length($snap);
my $replaced = substr($input, $insertion_start, $replaced_len);
print "Replaced sequence (first 100bp): $replaced\n";

# Check if the replacement is just a small segment
# Actually, let me think about this differently
# The output = input with egfp+flag+snap inserted at some point
# So: output = [input[0..insertion_start-1]] + [egfp] + [flag] + [snap] + [input[insertion_start..end]]

# Let me verify by checking if the output matches this reconstruction
my $reconstructed = substr($input, 0, $pos_egfp) . $egfp . $flag . $snap . substr($input, $pos_egfp);
if ($reconstructed eq $output) {
    print "\nVERIFIED: Output is input with egfp+flag+snap inserted at position $pos_egfp\n";
} else {
    print "\nReconstruction does not match output exactly\n";
    # Find where they diverge
    my $min_r = length($reconstructed) < length($output) ? length($reconstructed) : length($output);
    for my $i (0..$min_r-1) {
        if (substr($reconstructed, $i, 1) ne substr($output, $i, 1)) {
            print "Divergence at position $i\n";
            print "Reconstructed: ..." . substr($reconstructed, $i-20, 40) . "...\n";
            print "Output:        ..." . substr($output, $i-20, 40) . "...\n";
            last;
        }
    }
}

# Print the junction sequences for Golden Gate design
print "\n--- Junction analysis ---\n";
# Junction 1: input -> egfp
my $j1_input = substr($input, $pos_egfp - 20, 20);
my $j1_egfp = substr($egfp, 0, 20);
print "Junction 1 (input->egfp): input ends with '$j1_input', egfp starts with '$j1_egfp'\n";

# Junction 2: egfp -> flag
my $j2_egfp = substr($egfp, -20);
my $j2_flag = substr($flag, 0, 20);
print "Junction 2 (egfp->flag): egfp ends with '$j2_egfp', flag starts with '$j2_flag'\n";

# Junction 3: flag -> snap
my $j3_flag = substr($flag, -20);
my $j3_snap = substr($snap, 0, 20);
print "Junction 3 (flag->snap): flag ends with '$j3_flag', snap starts with '$j3_snap'\n";

# Junction 4: snap -> input
my $j4_snap = substr($snap, -20);
my $j4_input = substr($input, $pos_egfp, 20);
print "Junction 4 (snap->input): snap ends with '$j4_snap', input starts with '$j4_input'\n";
"}

