{"path":"analyze2.pl","content":"#!/usr/bin/perl
use strict;
use warnings;

# Parse FASTA
my %seqs;
my $name;
open my $fh, "<", "sequences.fasta" or die "Cannot open sequences.fasta: $!";
while (<$fh>) {
    chomp;
    if (/^>(\S+)/) {
        $name = $1;
        $seqs{$name} = "";
    } else {
        my $line = $_;
        $line =~ s/^\s+|\s+$//g;
        next if $line eq '';
        $seqs{$name} .= $line;
    }
}
close $fh;

my $egfp = $seqs{"egfp"};
my $flag = $seqs{"flag"};
my $snap = $seqs{"snap"};
my $input = $seqs{"input"};
my $output = $seqs{"output"};

print "Sequence lengths:\n";
for my $k (sort keys %seqs) {
    print "  $k: " . length($seqs{$k}) . " bp\n";
}

# The output is circular. Let's find where each fragment appears in the output.
# Since egfp, flag, snap are linear and may be modified at junctions,
# let's look for them with some tolerance.

# First, let's check if egfp appears exactly in the output
my $pos_egfp = index($output, $egfp);
print "\negfp exact match in output: position $pos_egfp\n";

# Check circularly (wrap around)
if ($pos_egfp < 0) {
    my $combined = $output . substr($output, 0, length($egfp));
    $pos_egfp = index($combined, $egfp);
    if ($pos_egfp >= length($output)) {
        $pos_egfp -= length($output);
    }
    print "egfp circular match: position $pos_egfp\n";
}

# Same for flag and snap
my $pos_flag = index($output, $flag);
print "flag exact match in output: position $pos_flag\n";
if ($pos_flag < 0) {
    my $combined = $output . substr($output, 0, length($flag));
    $pos_flag = index($combined, $flag);
    if ($pos_flag >= length($output)) {
        $pos_flag -= length($output);
    }
    print "flag circular match: position $pos_flag\n";
}

my $pos_snap = index($output, $snap);
print "snap exact match in output: position $pos_snap\n";
if ($pos_snap < 0) {
    my $combined = $output . substr($output, 0, length($snap));
    $pos_snap = index($combined, $snap);
    if ($pos_snap >= length($output)) {
        $pos_snap -= length($output);
    }
    print "snap circular match: position $pos_snap\n";
}

# Since exact matches fail, let's look for partial matches at the junctions
# The output should be: [input_part1] + [egfp_modified] + [flag_modified] + [snap_modified] + [input_part2]
# where modified means some bases are added/removed at junctions

# Let's find where egfp-like sequence starts in the output
# Look for the start of egfp (atgagcaagg...) in the output
my $egfp_start = "atgagcaagg";
my $pos_egfp_partial = index($output, $egfp_start);
print "\negfp partial match (atgagcaagg): position $pos_egfp_partial\n";

# Check if egfp appears starting from position 3 (without start codon)
my $egfp_no_start = substr($egfp, 3);
my $pos_egfp_nostart = index($output, $egfp_no_start);
print "egfp without start codon: position $pos_egfp_nostart\n";

# Check if egfp appears starting from position 1 (without first base)
my $egfp_no_first = substr($egfp, 1);
my $pos_egfp_1 = index($output, $egfp_no_first);
print "egfp without first base: position $pos_egfp_1\n";

# Let's look at the output around position 214 more carefully
print "\n--- Detailed analysis around position 214 ---\n";
my $region = substr($output, 200, 80);
print "Output[200..279]: $region\n";

# Check what's at the end of the output (circular junction)
print "\n--- End of output ---\n";
my $end_output = substr($output, -50);
print "Last 50bp of output: $end_output\n";
my $start_output = substr($output, 0, 50);
print "First 50bp of output: $start_output\n";

# Let's check if the end of snap connects to the beginning of input in the output
# snap ends with: gtaagcctgggctgggttaa
# input starts with: 

# Check if snap appears in the output
my $pos_snap2 = index($output, $snap);
print "\nsnap exact match: position $pos_snap2\n";

# Let's try to find snap by looking for unique regions
# snap has a distinctive region: gtaagcctgggctgggttaa at the end
my $snap_end = "gtaagcctgggctgggttaa";
my $pos_snap_end = index($output, $snap_end);
print "snap end (gtaagcctgggctgggttaa) in output: position $pos_snap_end\n";

# Let's also check the flag sequence
my $flag_start = "atgggtagtggctccggtagcggtagcggcagcgactacaaggacgacgacgacaagggttccggttctggttcaggtagtggttcataa";
my $pos_flag_exact = index($output, $flag_start);
print "flag exact match: position $pos_flag_exact\n";

# Let's try to find flag by looking for unique regions
my $flag_mid = "ggcagcgactacaaggacgacgacgacaagggttccggttctggttcaggtagtggttcataa";
my $pos_flag_mid = index($output, $flag_mid);
print "flag mid (ggcagcgactacaaggacgacgacgacaagggttccggttctggttcaggtagtggttcataa) in output: position $pos_flag_mid\n";

# Let me try a different approach - find where the input sequence reappears after the insertions
# The input has a distinctive region: atcagtctgattgcggcgtta (right after the insertion point)
my $input_after = "atcagtctgattgcggcgtta";
my $pos_input_after = index($output, $input_after);
print "\nInput sequence 'atcagtctgattgcggcgtta' in output: position $pos_input_after\n";

# Also check for the end of input
my $input_end = "gttgaatactcat";
my $pos_input_end = index($output, $input_end);
print "Input end 'gttgaatactcat' in output: position $pos_input_end\n";
"}

{"path":"analyze3.pl","content":"#!/usr/bin/perl
use strict;
use warnings;

my %seqs;
my $name;
open my $fh, "<", "sequences.fasta" or die;
while (<$fh>) {
    chomp;
    if (/^>(\S+)/) {
        $name = $1;
        $seqs{$name} = "";
    } else {
        my $line = $_;
        $line =~ s/^\s+|\s+$//g;
        next if $line eq '';
        $seqs{$name} .= $line;
    }
}
close $fh;

my $egfp = $seqs{"egfp"};
my $flag = $seqs{"flag"};
my $snap = $seqs{"snap"};
my $input = $seqs{"input"};
my $output = $seqs{"output"};

# egfp starts at position 210 in output
# Let's verify: output[0..210] should be input[0..210]
my $prefix = substr($output, 0, 210);
my $input_prefix = substr($input, 0, 210);
print "Prefix match (output vs input): ", ($prefix eq $input_prefix) ? "YES" : "NO", "\n";
if ($prefix ne $input_prefix) {
    for my $i (0..length($prefix)-1) {
        if (substr($prefix, $i, 1) ne substr($input_prefix, $i, 1)) {
            print "First mismatch at position $i\n";
            print "Output: ..." . substr($prefix, $i-5, 10) . "...\n";
            print "Input:  ..." . substr($input_prefix, $i-5, 10) . "...\n";
            last;
        }
    }
}

# After egfp (position 210+717=927), flag should start
my $after_egfp = substr($output, 210 + length($egfp), length($flag));
print "\nAfter egfp in output matches flag: ", ($after_egfp eq $flag) ? "YES" : "NO", "\n";

# After flag (position 927+90=1017), snap should start
my $after_flag = substr($output, 210 + length($egfp) + length($flag), length($snap));
print "After flag in output matches snap: ", ($after_flag eq $snap) ? "YES" : "NO", "\n";

# After snap (position 1017+549=1566), input[210..] should continue
my $after_snap = substr($output, 210 + length($egfp) + length($flag) + length($snap));
my $input_suffix = substr($input, 210);
print "After snap in output matches input[210..]: ", ($after_snap eq $input_suffix) ? "YES" : "NO", "\n";

if ($after_snap ne $input_suffix) {
    # Find where they diverge
    my $min_len = length($after_snap) < length($input_suffix) ? length($after_snap) : length($input_suffix);
    for my $i (0..$min_len-1) {
        if (substr($after_snap, $i, 1) ne substr($input_suffix, $i, 1)) {
            print "Divergence at position $i in suffix\n";
            print "Output: ..." . substr($after_snap, $i-5, 10) . "...\n";
            print "Input:  ..." . substr($input_suffix, $i-5, 10) . "...\n";
            last;
        }
    }
}

# Total check
my $reconstructed = $input_prefix . $egfp . $flag . $snap . $input_suffix;
print "\nFull reconstruction matches output: ", ($reconstructed eq $output) ? "YES" : "NO", "\n";

# Now let's look at the junctions more carefully
print "\n=== JUNCTION ANALYSIS ===\n";

# Junction 1: input -> egfp (position 210)
my $input_ending = substr($input, 200, 20);
my $egfp_starting = substr($egfp, 0, 20);
print "\nJunction 1 (input->egfp):\n";
print "  Input[200..219]: $input_ending\n";
print "  Egfp[0..19]:     $egfp_starting\n";

# Junction 2: egfp -> flag
my $egfp_ending = substr($egfp, -20);
my $flag_starting = substr($flag, 0, 20);
print "\nJunction 2 (egfp->flag):\n";
print "  Egfp[-20..-1]:   $egfp_ending\n";
print "  Flag[0..19]:     $flag_starting\n";

# Junction 3: flag -> snap
my $flag_ending = substr($flag, -20);
my $snap_starting = substr($snap, 0, 20);
print "\nJunction 3 (flag->snap):\n";
print "  Flag[-20..-1]:   $flag_ending\n";
print "  Snap[0..19]:     $snap_starting\n";

# Junction 4: snap -> input
my $snap_ending = substr($snap, -20);
my $input_starting = substr($input, 210, 20);
print "\nJunction 4 (snap->input):\n";
print "  Snap[-20..-1]:   $snap_ending\n";
print "  Input[210..229]: $input_starting\n";

# Now let's check the actual junction sequences in the output
print "\n=== ACTUAL JUNCTIONS IN OUTPUT ===\n";
my $j1 = substr($output, 205, 30);
print "Output around junction 1 (pos 205-234): $j1\n";

my $j2_pos = 210 + length($egfp);
my $j2 = substr($output, $j2_pos - 10, 30);
print "Output around junction 2 (pos ", $j2_pos-10, "-", $j2_pos+19, "): $j2\n";

my $j3_pos = 210 + length($egfp) + length($flag);
my $j3 = substr($output, $j3_pos - 10, 30);
print "Output around junction 3 (pos ", $j3_pos-10, "-", $j3_pos+19, "): $j3\n";

my $j4_pos = 210 + length($egfp) + length($flag) + length($snap);
my $j4 = substr($output, $j4_pos - 10, 30);
print "Output around junction 4 (pos ", $j4_pos-10, "-", $j4_pos+19, "): $j4\n";
"}

{"path":"analyze4.pl","content":"#!/usr/bin/perl
use strict;
use warnings;

my %seqs;
my $name;
open my $fh, "<", "sequences.fasta" or die;
while (<$fh>) {
    chomp;
    if (/^>(\S+)/) {
        $name = $1;
        $seqs{$name} = "";
    } else {
        my $line = $_;
        $line =~ s/^\s+|\s+$//g;
        next if $line eq '';
        $seqs{$name} .= $line;
    }
}
close $fh;

my $egfp = $seqs{"egfp"};
my $flag = $seqs{"flag"};
my $snap = $seqs{"snap"};
my $input = $seqs{"input"};
my $output = $seqs{"output"};

# Let's find the exact boundaries by checking each possible position
# where egfp could start in the output

# First, let's check if egfp appears at various offsets from position 210
for my $offset (-5..5) {
    my $pos = 210 + $offset;
    next if $pos < 0 || $pos > length($output) - length($egfp);
    my $match = 1;
    for my $i (0..length($egfp)-1) {
        if (substr($output, $pos+$i, 1) ne substr($egfp, $i, 1)) {
            $match = 0;
            last;
        }
    }
    print "egfp at output position ", 210+$offset, ": ", $match ? "EXACT MATCH" : "NO MATCH", "\n";
}

# Now check flag at various positions after egfp
my $egfp_pos = 210;
for my $offset (-5..5) {
    my $pos = $egfp_pos + length($egfp) + $offset;
    next if $pos < 0 || $pos > length($output) - length($flag);
    my $match = 1;
    for my $i (0..length($flag)-1) {
        if (substr($output, $pos+$i, 1) ne substr($flag, $i, 1)) {
            $match = 0;
            last;
        }
    }
    print "flag at output position ", $egfp_pos+length($egfp)+$offset, ": ", $match ? "EXACT MATCH" : "NO MATCH", "\n";
}

# Now check snap at various positions after flag
my $flag_pos = $egfp_pos + length($egfp);
for my $offset (-5..5) {
    my $pos = $flag_pos + length($flag) + $offset;
    next if $pos < 0 || $pos > length($output) - length($snap);
    my $match = 1;
    for my $i (0..length($snap)-1) {
        if (substr($output, $pos+$i, 1) ne substr($snap, $i, 1)) {
            $match = 0;
            last;
        }
    }
    print "snap at output position ", $flag_pos+length($flag)+$offset, ": ", $match ? "EXACT MATCH" : "NO MATCH", "\n";
}

# Let's also check if egfp appears with a 1-base shift (missing first base)
print "\n--- Checking egfp with shifted starts ---\n";
for my $shift (0..5) {
    my $egfp_sub = substr($egfp, $shift);
    my $pos = index($output, $egfp_sub);
    if ($pos >= 0) {
        print "egfp[", $shift, "..] found at output position $pos\n";
    }
}

# Check flag with shifted starts
print "\n--- Checking flag with shifted starts ---\n";
for my $shift (0..5) {
    my $flag_sub = substr($flag, $shift);
    my $pos = index($output, $flag_sub);
    if ($pos >= 0) {
        print "flag[", $shift, "..] found at output position $pos\n";
    }
}

# Check snap with shifted starts
print "\n--- Checking snap with shifted starts ---\n";
for my $shift (0..5) {
    my $snap_sub = substr($snap, $shift);
    my $pos = index($output, $snap_sub);
    if ($pos >= 0) {
        print "snap[", $shift, "..] found at output position $pos\n";
    }
}

