    }
}
close $fh;

my $egfp = $seqs{"egfp"};
my $flag = $seqs{"flag"};
my $snap = $seqs{"snap"};
my $input = $seqs{"input"};
my $output = $seqs{"output"};

# egfp matches at position 210 for 714 bp (missing last 3bp "taa")
# So output[210..923] = egfp[0..713]
# Then what's at output[924..]?

print "=== Junction analysis ===\n";

# Output around position 920-950
my $region = substr($output, 920, 60);
print "Output[920..979]: $region\n";

# egfp last 10bp: tggacgagctgtacaaataa
print "Egfp[-10..-1]: ", substr($egfp, -10), "\n";
# flag first 10bp: atgggtagtggc
print "Flag[0..9]:     ", substr($flag, 0, 10), "\n";

# Let's check what's at position 924 in output
for my $i (920..935) {
    my $match_egfp = 0;
    my $match_flag = 0;
    for my $j (0..9) {
        if ($i+$j < length($output)) {
            $match_egfp++ if substr($output, $i+$j, 1) eq substr($egfp, -10+$j, 1);
            $match_flag++ if substr($output, $i+$j, 1) eq substr($flag, $j, 1);
        }
    }
    print "Position $i: egfp_match=$match_egfp/10 flag_match=$match_flag/10\n";
}

# Let me check if the junction is: egfp[0..713] + [some bases] + flag
# The output at position 924 should be the start of flag or some overlap
print "\n=== Detailed junction 2 ===\n";
# Check if flag starts at various positions after egfp
for my $flag_start (920..935) {
    my $match_len = 0;
    for my $j (0..length($flag)-1) {
        last if $flag_start+$j >= length($output);
        if (substr($output, $flag_start+$j, 1) eq substr($flag, $j, 1)) {
            $match_len++;
        } else {
            last;
        }
    }
    if ($match_len > 5) {
        print "Flag starts at output position $flag_start with $match_len bp match\n";
        my $output_seq = substr($output, $flag_start, $match_len);
        my $flag_seq = substr($flag, 0, $match_len);
        if ($output_seq eq $flag_seq) {
            print "  EXACT MATCH: $output_seq\n";
        }
    }
}

# Let me also check if there's an overlap between egfp end and flag start
print "\n=== Checking for overlaps ===\n";
# Check if the end of egfp overlaps with the beginning of flag
for my $overlap (1..20) {
    my $egfp_suffix = substr($egfp, length($egfp)-$overlap);
    my $flag_prefix = substr($flag, 0, $overlap);
    if ($egfp_suffix eq $flag_prefix) {
        print "Overlap of $overlap bp: '$egfp_suffix'\n";
    }
}

# Check if the end of flag overlaps with the beginning of snap
for my $overlap (1..20) {
    my $flag_suffix = substr($flag, length($flag)-$overlap);
    my $snap_prefix = substr($snap, 0, $overlap);
    if ($flag_suffix eq $snap_prefix) {
        print "Flag-snap overlap of $overlap bp: '$flag_suffix'\n";
    }
}

# Check if the end of snap overlaps with the beginning of input (at position 210)
my $input_at_210 = substr($input, 210);
for my $overlap (1..20) {
    my $snap_suffix = substr($snap, length($snap)-$overlap);
    my $input_prefix = substr($input_at_210, 0, $overlap);
    if ($snap_suffix eq $input_prefix) {
        print "Snap-input overlap of $overlap bp: '$snap_suffix'\n";
    }
}

# Let me look at the actual output sequence more carefully
print "\n=== Actual output around junctions ===\n";
# Junction 1: input -> egfp (around position 210)
print "Output[205..220]: ", substr($output, 205, 15), "\n";
print "Input[205..220]:  ", substr($input, 205, 15), "\n";

# Junction 2: egfp -> flag (around position 924)
print "Output[920..940]: ", substr($output, 920, 20), "\n";

# Junction 3: flag -> snap (around position 1011)
print "Output[1005..1025]: ", substr($output, 1005, 20), "\n";

# Junction 4: snap -> input (around position 1554)
print "Output[1550..1570]: ", substr($output, 1550, 20), "\n";
print "Input[210..230]:    ", substr($input, 210, 20), "\n";

# Let me check if the output is: input[0..209] + egfp + flag + snap + input[210..end]
# with some bases at junctions
print "\n=== Testing reconstruction ===\n";
my $reconstructed = substr($input, 0, 210) . $egfp . $flag . $snap . substr($input, 210);
print "Reconstruction length: ", length($reconstructed), "\n";
print "Output length:        ", length($output), "\n";

# Find where they diverge
my $min_len = length($reconstructed) < length($output) ? length($reconstructed) : length($output);
for my $i (0..$min_len-1) {
    if (substr($reconstructed, $i, 1) ne substr($output, $i, 1)) {
        print "First divergence at position $i\n";
        print "Reconstructed: ...", substr($reconstructed, $i-5, 10), "...", substr($reconstructed, $i, 10), "...\n";
        print "Output:        ...", substr($output, $i-5, 10), "...", substr($output, $i, 10), "...\n";
        last;
    }
}

# Check if the difference is just at the junctions (extra bases)
# The output should be shorter than reconstruction if there are overlaps
my $diff = length($reconstructed) - length($output);
print "\nLength difference: $diff bp\n";
"}

