        $line =~ s/^\s+|\s+$//g;
        next if $line eq '';
        $seqs{$name} .= $line;
    }
}
close $fh;

my $egfp = $seqs{"egfp"};
my $flag = $seqs{"flag"};
my $snap = $seqs{"snap"};
my $input = $seqs{"input"};
my $output = $seqs{"output"};

# Let me find the exact mapping by checking each position
# egfp matched 714 bp starting at output[210]
# But let's check if it actually matches exactly or has mismatches

print "=== Exact egfp match check ===\n";
my $match_count = 0;
my $mismatch_positions = [];
for my $i (0..length($egfp)-1) {
    my $opos = 210 + $i;
    last if $opos >= length($output);
    if (substr($output, $opos, 1) eq substr($egfp, $i, 1)) {
        $match_count++;
    } else {
        push @$mismatch_positions, [$i, $opos];
    }
}
print "Match count: $match_count/" . length($egfp) . "\n";
print "Mismatch positions (egfp_pos, output_pos):\n";
for my $mp (@$mismatch_positions) {
    print "  egfp[$mp->[0]] = '" . substr($egfp, $mp->[0], 1) . "' vs output[$mp->[1]] = '" . substr($output, $mp->[1], 1) . "'\n";
}

# Now let's find where flag starts in the output
print "\n=== Finding flag start ===\n";
for my $i (0..length($output)-length($flag)) {
    my $match_len = 0;
    for my $j (0..length($flag)-1) {
        last if $i+$j >= length($output);
        if (substr($output, $i+$j, 1) eq substr($flag, $j, 1)) {
            $match_len++;
        } else {
            last;
        }
    }
    if ($match_len > 30) {
        print "Flag prefix match of length $match_len at output position $i\n";
        my $output_seq = substr($output, $i, $match_len);
        my $flag_seq = substr($flag, 0, $match_len);
        if ($output_seq eq $flag_seq) {
            print "  EXACT MATCH\n";
        } else {
            # Find first mismatch
            for my $j (0..$match_len-1) {
                if (substr($output, $i+$j, 1) ne substr($flag, $j, 1)) {
                    print "  First mismatch at position $j: output='" . substr($output, $i+$j, 1) . "' flag='" . substr($flag, $j, 1) . "'\n";
                    last;
                }
            }
        }
    }
}

# Find snap start
print "\n=== Finding snap start ===\n";
for my $i (0..length($output)-length($snap)) {
    my $match_len = 0;
    for my $j (0..length($snap)-1) {
        last if $i+$j >= length($output);
        if (substr($output, $i+$j, 1) eq substr($snap, $j, 1)) {
            $match_len++;
        } else {
            last;
        }
    }
    if ($match_len > 30) {
        print "Snap prefix match of length $match_len at output position $i\n";
        my $output_seq = substr($output, $i, $match_len);
        my $snap_seq = substr($snap, 0, $match_len);
        if ($output_seq eq $snap_seq) {
            print "  EXACT MATCH\n";
        } else {
            for my $j (0..$match_len-1) {
                if (substr($output, $i+$j, 1) ne substr($snap, $j, 1)) {
                    print "  First mismatch at position $j: output='" . substr($output, $i+$j, 1) . "' snap='" . substr($snap, $j, 1) . "'\n";
                    last;
                }
            }
        }
    }
}

# Let me also check if the fragments are in a different order or have overlaps
print "\n=== Checking all possible orders ===\n";
my @fragments = (['egfp', $egfp], ['flag', $flag], ['snap', $snap]);
my @orders = (
    [0,1,2], [0,2,1], [1,0,2], [1,2,0], [2,0,1], [2,1,0]
);

for my $order (@orders) {
    my $combined = "";
    for my $idx (@$order) {
        $combined .= $fragments[$idx][1];
    }
    # Check if this combined sequence appears in output (with some tolerance)
    my $best_score = 0;
    my $best_pos = -1;
    for my $i (0..length($output)-length($combined)) {
        my $score = 0;
        for my $j (0..length($combined)-1) {
            if (substr($output, $i+$j, 1) eq substr($combined, $j, 1)) {
                $score++;
            }
        }
        if ($score > $best_score) {
            $best_score = $score;
            $best_pos = $i;
        }
    }
    my $names = join("->", map { $fragments[$_][0] } @$order);
    printf "%-15s: score %d/%d at position %d\n", $names, $best_score, length($combined), $best_pos;
}
"}

