{"path":"analyze10.pl","content":"#!/usr/bin/perl
use strict;
use warnings;

my %seqs;
my $name;
open my $fh, "<", "sequences.fasta" or die;
while (<$fh>) {
    chomp;
    if (/^>(\S+)/) {
        $name = $1;
        $seqs{$name} = "";
    } else {
        my $line = $_;
        $line =~ s/^\s+|\s+$//g;
        next if $line eq '';
        $seqs{$name} .= $line;
    }
}
close $fh;

my $egfp = $seqs{"egfp"};
my $flag = $seqs{"flag"};
my $snap = $seqs{"snap"};
my $input = $seqs{"input"};
my $output = $seqs{"output"};

# Let me find the exact start of each fragment in the output by checking
# all possible starting positions and finding the longest exact prefix match

sub find_longest_prefix_match {
    my ($target, $text) = @_;
    my $best_len = 0;
    my $best_pos = -1;
    for my $i (0..length($text)-1) {
        my $len = 0;
        for my $j (0..length($target)-1) {
            last if $i+$j >= length($text);
            if (substr($text, $i+$j, 1) eq substr($target, $j, 1)) {
                $len++;
            } else {
                last;
            }
        }
        if ($len > $best_len) {
            $best_len = $len;
            $best_pos = $i;
        }
    }
    return ($best_pos, $best_len);
}

for my $frag_name (qw(egfp flag snap)) {
    my $frag = $seqs{$frag_name};
    my ($pos, $len) = find_longest_prefix_match($frag, $output);
    print "$frag_name: best prefix match of $len bp at output position $pos\n";
    if ($len > 0 && $pos >= 0) {
        # Print the matched region
        my $matched_output = substr($output, $pos, $len);
        my $matched_frag = substr($frag, 0, $len);
        print "  Output[$pos..$pos+$len-1]: $matched_output\n";
        print "  Frag[0..$len-1]:           $matched_frag\n";
        if ($matched_output eq $matched_frag) {
            print "  EXACT MATCH\n";
        } else {
            # Find first mismatch
            for my $j (0..$len-1) {
                if (substr($matched_output, $j, 1) ne substr($matched_frag, $j, 1)) {
                    print "  First mismatch at position $j: output='" . substr($matched_output, $j, 1) . "' frag='" . substr($matched_frag, $j, 1) . "'\n";
                    last;
                }
            }
        }
    }
}

# Now let me check if the fragments appear with a shift (missing N bases from start)
print "\n=== Checking for shifted starts ===\n";
for my $frag_name (qw(egfp flag snap)) {
    my $frag = $seqs{$frag_name};
    for my $shift (0..10) {
        my $sub = substr($frag, $shift);
        my ($pos, $len) = find_longest_prefix_match($sub, $output);
        if ($len > length($frag) - 5) {
            print "$frag_name shifted by $shift: match of $len bp at output position $pos\n";
            if ($len == length($sub)) {
                print "  FULL MATCH!\n";
            }
        }
    }
}

# Let me also check the reverse complement
print "\n=== Reverse complement check ===\n";
sub rc {
    my $seq = uc(shift);
    $seq =~ tr/ACGTacgt/TGCAtgca/;
    return scalar reverse($seq);
}

for my $frag_name (qw(egfp flag snap)) {
    my $rc_seq = rc($seqs{$frag_name});
    my ($pos, $len) = find_longest_prefix_match($rc_seq, $output);
    print "$frag_name RC: best prefix match of $len bp at output position $pos\n";
}

# Let me also check if the fragments appear in a different order
print "\n=== Checking all possible orders ===\n";
my @fragments = (['egfp', $egfp], ['flag', $flag], ['snap', $snap]);
my @orders = (
    [0,1,2], [0,2,1], [1,0,2], [1,2,0], [2,0,1], [2,1,0]
);

for my $order (@orders) {
    my $combined = "";
    for my $idx (@$order) {
        $combined .= $fragments[$idx][1];
    }
    my ($pos, $len) = find_longest_prefix_match($combined, $output);
    my $names = join("->", map { $fragments[$_][0] } @$order);
    printf "%-15s: best match %d/%d at position %d\n", $names, $len, length($combined), $pos;
}
"}

