        if ($len > $best_len) {
            $best_len = $len;
            $best_pos = $i;
        }
    }
    my $names = join("->", map { $fragments[$_][0] } @$order);
    printf "%-15s: best match %d/%d at position %d\n", $names, $best_len, length($combined), $best_pos;
}

# Let me also check if the fragments are in the order egfp -> snap -> flag
