    for my $j (0..length($sub)-1) {
        last if 1554+$j >= length($output);
        if (substr($output, 1554+$j, 1) eq substr($sub, $j, 1)) {
            $mlen++;
        } else {
            last;
        }
    }
    print "input[210+$shift..] match: $mlen bp\n";
}

# Let me also check if the output wraps around
# output is circular, so output[3591..] = output[0..]
print "\n=== Checking if output wraps ===\n";
# Check if output[1554..] + output[0..209] matches input[210..]
my $combined_output = substr($output, 1554) . substr($output, 0, 210);
print "Combined length: ", length($combined_output), "\n";
print "input[210..] length: ", length(substr($input, 210)), "\n";

my $mlen = 0;
for my $j (0..length($combined_output)-1) {
    last if $j >= length($input) - 210;
    if (substr($combined_output, $j, 1) eq substr($input, 210+$j, 1)) {
        $mlen++;
    } else {
        last;
    }
}
print "Combined output matches input[210..]: $mlen bp\n";

# Let me also check the reverse: does input[210..] + input[0..209] match output?
