print "\nInserted sequence length: ", length($inserted), "\n";
print "Expected inserted length: ", length($egfp) + length($flag) + length($snap), "\n";

# Actually, let me just check if output[1554..] matches input[210..] for the full remaining length
my $remaining_input = length($input) - 210;
print "\nRemaining input after position 210: $remaining_input bp\n";
print "Output from 1554 to end: ", length($output) - 1554, " bp\n";

# Check if output[1554..] matches input[210..] for min of both lengths
