print "Min length to compare: $min_len\n";

my $mlen = 0;
for my $j (0..$min_len-1) {
    if (substr($output, 1554+$j, 1) eq substr($input, 210+$j, 1)) {
        $mlen++;
    } else {
        last;
    }
}
print "Match length: $mlen\n";

# If they match for the full output length from 1554, check what happens next
if ($mlen == length($output) - 1554) {
